var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"아아…… 아아아아아악!!","JPN":"ああ……ああああああ！！","ENG":"Ah... AAAAAHHHHH!!!","TWN":"啊啊……！啊啊啊啊啊啊！！"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"내려 줘! 여기서 풀어 줘……!","JPN":"下ろして！　放してよ……！","ENG":"Let me down! Let me out of here...!","TWN":"放我下去！快放開我……！"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"몸이, 몸이 너무 아파! 아각, 아가아아아악!","JPN":"体が、体が痛いよ！　がはっ、ああああああっ！","ENG":"My, my body, it hurts so much! Gah, AAAAGHHH!","TWN":"好痛，身體好痛！啊啊，啊啊啊啊！"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"사람들이 전부 하늘로 떠오르잖아……?","JPN":"人がみんな宙に浮いてる……？","ENG":"The people are all being pulled up to the sky…?","TWN":"人怎麼都浮在空中……？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이게 어떻게 된 거예요, 에클레시아?","JPN":"これはいったいどういうことですか、エクレシア？","ENG":"What is going on here, Ecclesia?","TWN":"這到底是怎麼回事，艾可露西亞？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"타기리온의 권능이다.","JPN":"タギリオンの権能だ。","ENG":"It is the power of Thagirion.","TWN":"是塔基里翁的能力。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"서둘러야겠구나. 과거의 경험이라 한들 너무 오래 머물면 너 역시 영향을 받을 터.","JPN":"急がねばならぬ。過去の経験とはいえ、長居すればそなたもまた影響を受けよう。","ENG":"We must hurry. Though this may be a past experience, it will affect you the longer you stay.","TWN":"動作要快，在這過去的記憶中待太久的話，你也會受到影響。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"타기리온에게 말인가요?","JPN":"タギリオンにですか？","ENG":"Affected by Thagirion?","TWN":"受到塔基里翁的影響？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"얼마나 위험하길래 그래요? 국가적인 위협이라면─","JPN":"そんなに危険なんですか？　国家的な脅威なら──","ENG":"How dangerous is that? If it's close to a national threat–","TWN":"到底有多危險？竟然說是國家級的威脅……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"……30초.","JPN":"……30秒。","ENG":"...30 seconds.","TWN":"……30秒。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네?","JPN":"え？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"30초 뒤면, 성흔을 얻지 못한 이 세계의 모든 지성체가 전멸한다.","JPN":"30秒後には、聖痕を得られなかったこの世界のすべての知性体が全滅する。","ENG":"In 30 seconds, all those without the Stigmata will be wiped from this world.","TWN":"30秒後，這世上沒得到聖痕的所有智慧生命都將會消逝。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"30초라니요? 여기가 초고심도 이면세계라도 된단 말이에요?","JPN":"30秒？　ここが超高深度の裏世界にでもなったっていうんですか？","ENG":"30 seconds? Do you mean this world is going to become the hyperdepths of Counterside?","TWN":"30秒？難道這裡會變成超深度異界？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"사람들이…… 변하고 있어? 급성 침식 증후군인가?","JPN":"人々が……変化してる？　急性の侵食症候群なの？","ENG":"Those people... are starting to mutate? Is this an acute Corruption Syndrome?","TWN":"大家……正在發生異變？是急性侵蝕症候群？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아냐…. 저건 마치…….","JPN":"違う……あれはまるで……","ENG":"No... This is as if...","TWN":"不對……這簡直就像是……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"골격이, 종 자체가 뒤틀리는 듯한…….","JPN":"骨格が、生物としての種類も変えられているような……","ENG":"Their skeleton, their species itself is twisting...","TWN":"不只是骨骼，感覺是完全變成另一個種類……"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"물러서라, 레아!","JPN":"下がれ、レア！","ENG":"Stand back, Leah!","TWN":"蕾亞，退後！"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"아아, 여기 아직 축복 받지 못한 이들이 남아 있었구나.","JPN":"ああ、こちらにまだ祝福を受けていない者たちが残っていたのね。","ENG":"Ahh, I see there are still those who have not been blessed.","TWN":"哼，這裡竟然還有沒得到祝福的人。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L28_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"하지만 두려워 말렴. 너희 또한 우리와 같이 자매가 될 수 있어.","JPN":"だが、怖がることはない。お前らもまた、私たちのように姉妹になれるわ。","ENG":"But do not worry. For you both can also join our sisterhood.","TWN":"不用害怕，你們也會變得和我們姊妹一樣。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"안식을 취하라, 희생양이여. 위대한 정적의 이름으로 허락할지니.","JPN":"安息せよ、犠牲者よ。偉大なる静寂の名で許そう。","ENG":"Rest, oh, scapegoat. The Great Silence will allow it.","TWN":"犧牲品，我以偉大的靜寂之名賜予你安息。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"─아, 아아.","JPN":"──あ、ああ。","ENG":"–Ah... Aah...","TWN":"─啊啊啊。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"아, 하하하, 아하하하하──","JPN":"ア、ハハハ、アハハハハ──","ENG":"Ah, hah hah hah! Ah hah hah hah hah──","TWN":"哈哈哈，哈哈哈哈哈──"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_LAUGH"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"가자. 믿음 있는 자들이 스러진 이상, 나 역시 저들을 오래 상대할 수는 없다.","JPN":"行こう。信ずる者たちが倒れた以上、我もまたあの者たちと長く対することはできぬ。","ENG":"We must depart. I cannot fight them for long as well, for the faithed have fallen.","TWN":"走吧，既然有信念的人已消失，我也無法撐太久。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MINISTRA_CORRUPT_NULL_SHADOW","face":"UNIT_LAUGH"},"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"끄아아아악!","JPN":"クアアアアッ！","ENG":"Gaaaah!","TWN":"啊啊啊啊啊！"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"그만, 해. 등이. 찢어질 거 같아. 아, 뽑지 마, 뽑지 마, 뽑지 마아──","JPN":"やめ、て。背中が。裂けそう。あ、抜かないで、抜かないで、抜かないで――","ENG":"Stop, it. My back feels, like it's being torn. No, don't pull it out. No...! DON'T––","TWN":"住，手。背好像，要裂開了。啊，不要，不要拔，不要──"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"에클레시아, 설명해 줘요. 상황이 어떻게 돌아가고 있는 거죠?","JPN":"エクレシア、説明してください。この状況はいったいどうなっているんですか？","ENG":"Ecclesia, please explain. What exactly is going on here?","TWN":"艾可露西亞，快告訴我，這到底是怎麼回事？"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하늘에 나타나는 저것들은…… 데몬 타입 침식체잖아요.","JPN":"宙に浮いているあれらは……デーモンタイプの侵食体じゃないですか。","ENG":"Those things that appeared in the sky... They are Demon-type C.O.s.","TWN":"空中出現的……明明只是惡魔型侵蝕體。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"어떻게 평범한 사람들이 그림자로 변하는 거죠?","JPN":"どうして普通の人がシャドウに変わるんですか？","ENG":"But how are normal people turning into Shadows?","TWN":"為什麼一般人也會變成暗影？"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그 아이가 실험관을 보고 울부짖던 것과 관련이 있는 건가요?","JPN":"あの子が実験室を見て泣き叫んでたのと関係があるんですか？","ENG":"Does this have anything to do with that child crying after seeing the vat?","TWN":"是不是和那孩子看到實驗試管後的哀號聲有關？"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"나는 그 아이와 약속했다.","JPN":"我はあの子と約束した。","ENG":"I made a vow to that child.","TWN":"我有答應那孩子，"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"마왕을 쓰러뜨린 뒤, 헤어진 자매를 다시 만나게 해 주겠노라고.","JPN":"魔王を倒した後、生き別れた姉にもう一度会わせてやると。","ENG":"That, after defeating the Demon Lord, I would reunite her with her sister.","TWN":"等擊敗魔王後，會讓她與失散的姊姊重逢。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"하지만 그 아이의 자매는….","JPN":"しかし、あの子の姉は……","ENG":"But her sister was...","TWN":"但是那孩子的姊姊……"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네가 목격한 대로 이미 멘탈 프린팅 실험에 희생된 뒤였다.","JPN":"そなたが目撃したとおり、すでにメンタル・プリンティングの実験の犠牲となった後であった。","ENG":"already sacrificed in the Mental Printing experiment like you witnessed.","TWN":"如你所見，已經犧牲於智力複印實驗。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……멘탈 프린팅의 목적은.","JPN":"……メンタル・プリンティングの目的は。","ENG":"...And the purpose of Mental Printing is.","TWN":"智力複印的目的……"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"나와 같은 성흔을 지닌 존재들을 만들어내는 것이었지.","JPN":"我と同じ聖痕を持つ存在を作り出すことである。","ENG":"To create beings blessed with the Stigmata, similar to me.","TWN":"就是創造出和我一樣擁有聖痕的存在。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"믿음으로부터 힘을 얻는다고 한들, 내 수명은 유한하다.","JPN":"信仰から力を得るとは言え、我の寿命は有限だ。","ENG":"My fortitude may come from faith, but my time is finite.","TWN":"雖然可以從信仰中得到力量，但我的壽命是有限的。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"죽여도 죽지 않는 신.","JPN":"殺しても死なない神。","ENG":"A god that cannot perish even when it is killed.","TWN":"擁有不死之身的神，"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그런 신들이 집결한 만신전.","JPN":"そのような神々が集結した万神殿。","ENG":"A pantheon composed of such gods.","TWN":"將這些神聚集在一起的萬神殿，"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그리고 이견 없는 하나된 교리 아래에서 신앙할 성도들.","JPN":"そして、異見なく一つとなった教理の元で信仰するであろう信徒たち。","ENG":"And followers of faith under a united doctrine.","TWN":"以及信仰著相同教義的信徒們，"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"적어도…. 교단과 네퀴티아는 그것만이 멸망에 맞설 방책이라고 믿었다.","JPN":"少なくとも……教団とネキティアは、それだけが滅亡に立ち向かう方策であると信じていたのだ。","ENG":"At least... that is what the Order and Nequitia believed to be the only way to prevent devastation.","TWN":"教團和莉奎蒂亞認為…唯有這是能夠與滅亡抗衡的對策。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"잠깐만요. 그럼 당신은 네퀴티아가 추구하던 성공이란 뜻이잖아요.","JPN":"ちょっと待ってください。じゃあ、あなたはネキティアが追求していた成功例ってことじゃないですか。","ENG":"Hold on. Then that means you are the success that Nequitia has been pursuing.","TWN":"等等，這麼說來，其實你就是莉奎蒂亞在追求的成功。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그런데 열차에 있다는 뜻은…….","JPN":"でも、列車にいるってことは……","ENG":"But your being on this train means...","TWN":"但你為什麼會在列車裡……"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 이상은 발설하지 말지어다. 아이가 우리 존재를 알아챘구나.","JPN":"それ以上は口にするな。あの子が我々の存在に気付いた。","ENG":"No more of this subject. The child is aware of our existence.","TWN":"別再說了，那孩子已經發現我們的存在。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"역병에 희생된 이들이 포악하여도 두려워 말라. 곧 기관실에 당도할 터이니.","JPN":"疫病の犠牲となった者たちが凶暴であろうとも、恐れるな。時待たずして機関室に着くであろう。","ENG":"The scapegoats of the plague may exhibit cruelty, but do not be afraid. We will reach the engine room soon enough.","TWN":"不要害怕那些被瘟疫犧牲之人，我們馬上就能抵達控制室。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"처음 만났을 때 보여 줬던 섬광은 못 쓰나요?","JPN":"初めて会った時に見せてくれた閃光は、もう使えないんですか？","ENG":"Can't you use that flash of light that you used when we first met?","TWN":"你現在不能施展第一次見面時用過的那閃光嗎？"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이 시기에는 그러하다. 그 아이의 화만 돋울 뿐이겠지.","JPN":"今は。あの子をなおさら怒らせるだけだ。","ENG":"Not at this time. It will only anger the child further.","TWN":"現在如果使用的話，只會更加激怒那孩子。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"역시 당신은 신이라기엔 신경 쓰는 것들이 너무 많아요.","JPN":"やっぱりあなたは神というわりには制約が多すぎますね。","ENG":"For a god, I think you take too much stuff into consideration.","TWN":"你這個神的顧慮還真多。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"제 몸은 제 힘으로 어떻게든 지켜 볼게요.","JPN":"私の体は自分でなんとか守ってみます。","ENG":"I'll try to take care of myself.","TWN":"那我只好自我保護。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아까처럼 감당 못할 녀석들만 잘 부탁해요, 에클레시아.","JPN":"さっきみたいに、手に負えないやつらだけよろしくお願いします、エクレシア。","ENG":"Just take care of those that I can't handle, like last time, Ecclesia.","TWN":"跟剛才一樣，我對付不了的傢伙都交給你，艾可露西亞。"},"stage":{"bg":"TRAIL","bgm":"THEMA_SECURITY_AGENT_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};